-- ═══ 2 John Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 John', 1, 'kids', 1, 'Who wrote the letter of 2 John?', 'The elder (John)', 'Paul', 'Peter', 'James', 'a', '2 John 1:1 — "The elder unto the elect lady and her children."'),
('2 John', 1, 'kids', 2, 'What commandment does John say we should follow?', 'That we love one another', 'That we be rich', 'That we build big churches', 'That we travel far', 'a', '2 John 1:5 — "that we love one another."'),
('2 John', 1, 'kids', 3, 'What did John say about people who deny Jesus came in the flesh?', 'They are deceivers', 'They are wise teachers', 'They are friends', 'They are angels', 'a', '2 John 1:7 — "many deceivers are entered into the world, who confess not that Jesus Christ is come in the flesh. This is a deceiver and an antichrist."'),
-- Teens
('2 John', 1, 'teens', 1, 'To whom is the letter of 2 John addressed?', 'The elect lady and her children', 'The church at Ephesus', 'Timothy', 'The twelve apostles', 'a', '2 John 1:1 — "The elder unto the elect lady and her children, whom I love in the truth."'),
('2 John', 1, 'teens', 2, 'What does John say about the commandment to love one another?', 'It is not a new commandment but one we had from the beginning', 'It was just given by Jesus at the Last Supper', 'It replaces the Ten Commandments', 'It only applies to church leaders', 'a', '2 John 1:5 — "not as though I wrote a new commandment unto thee, but that which we had from the beginning."'),
('2 John', 1, 'teens', 3, 'What does John say walking in love means?', 'Walking after His commandments', 'Feeling happy all the time', 'Never disagreeing with anyone', 'Giving away all possessions', 'a', '2 John 1:6 — "this is love, that we walk after his commandments."'),
('2 John', 1, 'teens', 4, 'What does John warn about those who go beyond the doctrine of Christ?', 'They do not have God; he that abides in the doctrine has both the Father and the Son', 'They are the most advanced Christians', 'They have special revelation', 'They should be made leaders', 'a', '2 John 1:9 — "Whosoever transgresseth, and abideth not in the doctrine of Christ, hath not God."'),
('2 John', 1, 'teens', 5, 'What does John say to do with someone who does not bring the doctrine of Christ?', 'Do not receive him into your house or bid him God speed', 'Welcome him warmly and debate him', 'Ignore him completely', 'Report him to the Romans', 'a', '2 John 1:10 — "If there come any unto you, and bring not this doctrine, receive him not into your house, neither bid him God speed."'),
-- Adults
('2 John', 1, 'adults', 1, 'What is the significance of John calling himself "the elder" rather than "the apostle"?', 'It emphasizes his pastoral authority and relationship rather than apostolic rank, suggesting a letter of personal care to a specific community', 'He had lost his apostolic status', 'He was too old to be called an apostle', 'It was a required title for all church leaders', 'a', '2 John 1:1 — "The elder" — John uses this intimate title showing pastoral relationship.'),
('2 John', 1, 'adults', 2, 'What does John mean when he says he loves the elect lady "in the truth"?', 'His love is grounded in and motivated by divine truth — not merely human affection but love rooted in the gospel', 'He is being legally truthful', 'He loves her more than others', 'He is writing a formal legal document', 'a', '2 John 1:1 — "whom I love in the truth; and not I only, but also all they that have known the truth."'),
('2 John', 1, 'adults', 3, 'What specific heresy does John identify in verse 7?', 'Denying that Jesus Christ is come in the flesh — an early form of Docetism or Gnostic teaching', 'Denying the resurrection of the dead', 'Teaching that there are many gods', 'Rejecting the Old Testament entirely', 'a', '2 John 1:7 — "many deceivers… who confess not that Jesus Christ is come in the flesh. This is a deceiver and an antichrist."'),
('2 John', 1, 'adults', 4, 'What does John say believers should "look to" regarding their work?', '"Look to yourselves, that we lose not those things which we have wrought, but that we receive a full reward"', '"Look to the heavens for signs of His coming"', '"Look to the poor and needy around you"', '"Look to the elders for guidance in all things"', 'a', '2 John 1:8 — "Look to yourselves, that we lose not those things which we have wrought, but that we receive a full reward."'),
('2 John', 1, 'adults', 5, 'What is the doctrinal test John gives for distinguishing true from false teachers?', 'Whether they abide in the doctrine of Christ — those who transgress and do not abide in it have not God', 'Whether they can perform miracles', 'Whether they were trained by the apostles', 'Whether they have large followings', 'a', '2 John 1:9 — "Whosoever transgresseth, and abideth not in the doctrine of Christ, hath not God. He that abideth in the doctrine of Christ, he hath both the Father and the Son."'),
('2 John', 1, 'adults', 6, 'What does "bid him God speed" mean in the context of verse 10, and why is it prohibited?', 'Greeting a false teacher with blessing makes one a partaker of his evil deeds — it implies endorsement of his teaching', 'It means wishing someone a safe journey', 'It is a form of financial support', 'It means praying for their conversion', 'a', '2 John 1:11 — "he that biddeth him God speed is partaker of his evil deeds."'),
('2 John', 1, 'adults', 7, 'Why does John say he chose not to write with paper and ink?', 'He hopes to come and speak face to face, that their joy may be full', 'He ran out of writing materials', 'The subject was too sensitive for a letter', 'He wanted Timothy to deliver the message verbally', 'a', '2 John 1:12 — "I would not write with paper and ink: but I trust to come unto you, and speak face to face, that our joy may be full."'),
('2 John', 1, 'adults', 8, 'Who sends greetings at the close of the letter?', 'The children of the elect lady''s sister', 'The church at Jerusalem', 'Paul and Timothy', 'The seven churches of Asia', 'a', '2 John 1:13 — "The children of thy elect sister greet thee."');
